SELECT name
FROM apparel_items
WHERE is_pre_order = 1;

SELECT variation_name, exclusive_event
FROM item_variations
WHERE is_exclusive = 1;

SELECT COUNT(*) AS pre_order_items_count
  FROM apparel_items
  WHERE is_pre_order = 1;

SELECT item_id, total_reviews
FROM apparel_items
ORDER BY total_reviews DESC;

SELECT name, buy_price, popularity_score
FROM apparel_items
WHERE buy_price = (SELECT MAX(buy_price) FROM apparel_items);

SELECT AVG(rating) AS average_rating
FROM apparel_items
WHERE is_pre_order = 1 AND popularity_score > 8.0;

SELECT name
FROM apparel_items
WHERE popularity_score = (SELECT MAX(popularity_score) FROM apparel_items);
